<!DOCTYPE html>
<html>
<head>
  <title>Maze Game</title>
  <style>
    body {
      font-family: sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
    }

    #maze {
      border: 1px solid black;
      width: 400px;
      height: 400px;
      position: relative;
    }

    .cell {
      width: 10px;
      height: 10px;
      background-color: white;
      position: absolute;
    }

    .wall-n {
      border-top: 1px solid black;
    }

    .wall-e {
      border-right: 1px solid black;
    }

    .wall-s {
      border-bottom: 1px solid black;
    }

    .wall-w {
      border-left: 1px solid black;
    }

    .bot {
      width: 8px;
      height: 8px;
      position: absolute;
      border-radius: 50%;
    }

    #completed {
      margin-top: 10px;
    }

    #timer {
      margin-top: 10px;
    }

    button {
      padding: 10px 20px;
      font-size: 16px;
      cursor: pointer;
    }
  </style>
</head>
<body>
  <h1>Maze Game</h1>
  <div id="maze"></div>
  <div id="completed">Completed: 0</div>
  <div id="timer">Timer: 0</div>
  <button id="reset">Reset</button>

  <script>
    const mazeElement = document.getElementById('maze');
    const completedElement = document.getElementById('completed');
    const timerElement = document.getElementById('timer');
    const resetButton = document.getElementById('reset');

    let rows = 20;
    let cols = 20;
    let mazeData = [];
    let bots = [];
    let gameTimer = 0;
    let lastBotFinishTick = null;
    let isFrozen = false;

    const exitCell = { r: rows - 1, c: cols - 1 };

    function generateMaze() {
      mazeData = Array(rows).fill(null).map(() => Array(cols).fill(0));
      for (let i = 0; i < rows; i++) {
        for (let j = 0; j < cols; j++) {
          if (i === 0 || i === rows - 1 || j === 0 || j === cols - 1) {
            mazeData[i][j] = 1; // Walls around the border
          } else {
            // Simple random maze generation for demonstration.  A real implementation would use a proper algorithm.
            if (Math.random() < 0.3) mazeData[i][j] = 1;
          }
        }
      }
    }

    function createMazeVisual() {
      mazeElement.innerHTML = '';
      for (let i = 0; i < rows; i++) {
        for (let j = 0; j < cols; j++) {
          const cell = document.createElement('div');
          cell.classList.add('cell');

          if (mazeData[i][j] === 1) {
            cell.classList.add('wall-n', 'wall-e', 'wall-s', 'wall-w');
          }

          mazeElement.appendChild(cell);
        }
      }
    }

    function createBot(r, c) {
      const bot = {
        r: r,
        c: c,
        path: [],
        deadEnds: [],
        finishTick: null,
      };
      bots.push(bot);
      const botElement = document.createElement('div');
      botElement.classList.add('bot');
      botElement.style.left = (c * 10) + 'px';
      botElement.style.top = (r * 10) + 'px';
      mazeElement.appendChild(botElement);
      return bot;
    }

    function moveBot(bot) {
      const directions = ['n', 'e', 's', 'w'];
      shuffleArray(directions);

      for (const dir of directions) {
        let newR = bot.r;
        let newC = bot.c;

        if (dir === 'n') newR--;
        else if (dir === 'e') newC++;
        else if (dir === 's') newR++;
        else if (dir === 'w') newC--;

        if (newR >= 0 && newR < rows && newC >= 0 && newC < cols && mazeData[newR][newC] === 0) {
          bot.path.push({ r: newR, c: newC });
          bot.r = newR;
          bot.c = newC;

          // Check for dead end
          if (bots.filter(b => b !== bot).every(b => !isAdjacent(bot.r, bot.c, b.r, b.c))) {
            bot.deadEnds.push({ r: bot.r, c: bot.c });
          }

          // Update bot position visually
          const botElement = document.querySelector(`.bot[style*="top=${bot.r * 10}px;left=${bot.c * 10}px;"]`);
          if (botElement) {
            botElement.style.left = (bot.c * 10) + 'px';
            botElement.style.top = (bot.r * 10) + 'px';
          }

          break; // Move only once per tick
        }
      }
    }

    function isAdjacent(r1, c1, r2, c2) {
      return Math.abs(r1 - r2) <= 1 && Math.abs(c1 - c2) <= 1;
    }


    function shuffleArray(array) {
      for (let i = array.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [array[i], array[j]] = [array[j], array[i]];
      }
    }

    function updateGameDisplay() {
      completedElement.textContent = bots.filter(bot => bot.finishTick !== null).length;
      timerElement.textContent = 'Timer: ' + gameTimer;
    }


    function tick() {
      if (isFrozen) return;
      gameTimer++;
      updateGameDisplay();

      bots.forEach(bot => {
        if (bot.finishTick === null) {
          moveBot(bot);
        }
      });

      // Check if all bots have finished
      if (bots.every(bot => bot.finishTick !== null)) {
        isFrozen = true;
        lastBotFinishTick = gameTimer;
      }
    }

    function resetGame() {
      generateMaze();
      createMazeVisual();
      bots = [];
      gameTimer = 0;
      lastBotFinishTick = null;
      isFrozen = false;
      bots.forEach(bot => bot.path = []);
      bots.forEach(bot => bot.deadEnds = []);
      updateGameDisplay();
    }

    resetButton.addEventListener('click', resetGame);

    // Initial setup
    generateMaze();
    createMazeVisual();
    for (let i = 0; i < 24; i++) {
      const bot = createBot(Math.floor(rows / 2), Math.floor(cols / 2));
    }


    // Game loop
    setInterval(tick, 100);
  </script>
</body>
</html>
